const items = $input.all();
const hoy = new Date();
const diaHoy = hoy.getDate();
const mesHoy = hoy.getMonth() + 1;

const cumpleaneros = [];

for (const item of items) {
  const fecha = item.json.fecha_nacimiento;
  if (!fecha) continue;

  const partes = fecha.split('/');
  if (partes.length !== 3) continue;

  const dia = parseInt(partes[0]);
  const mes = parseInt(partes[1]);
  const anio = parseInt(partes[2]);

  if (dia === diaHoy && mes === mesHoy) {
    const edad = hoy.getFullYear() - anio;
    cumpleaneros.push({
      json: {
        nombre_alumno: item.json.nombre_alumno,
        curso: item.json.curso,
        email_tutor: item.json.email_tutor,
        edad: edad,
        hay_cumpleanos: true
      }
    });
  }
}

if (cumpleaneros.length === 0) {
  return [{ json: { hay_cumpleanos: false } }];
}

// Agrupar por tutor para enviar un solo email por curso
const porTutor = {};
for (const c of cumpleaneros) {
  const email = c.json.email_tutor;
  if (!porTutor[email]) {
    porTutor[email] = {
      email_tutor: email,
      curso: c.json.curso,
      alumnos: []
    };
  }
  porTutor[email].alumnos.push(`${c.json.nombre_alumno} (cumple ${c.json.edad} anos)`);
}

return Object.values(porTutor).map(grupo => ({
  json: {
    email_tutor: grupo.email_tutor,
    curso: grupo.curso,
    lista_cumpleaneros: grupo.alumnos.join('\n- '),
    total: grupo.alumnos.length,
    hay_cumpleanos: true
  }
}));
